css:
.notfound-wrap {
  text-align: center;
  padding: 80px 20px;
}
.notfound-icon {
  font-size: 4rem;
  animation: bounce 1.8s ease-in-out infinite;
}
.notfound-code {
  font-size: 6rem;
  font-weight: bold;
  color: #f90;
  line-height: 1;
  margin: 10px 0;
}
.notfound-msg {
  color: #666;
  margin: 20px 0 32px;
  line-height: 1.8;
}
.notfound-btn {
  display: inline-block;
  padding: 10px 28px;
  background: #f90;
  color: #fff;
  border-radius: 999px;
  text-decoration: none;
  font-weight: bold;
}
.notfound-btn:hover {
  background: #e68a00;
}
@keyframes bounce {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-12px); }
}
